INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  241,
  'Post-Partum Breast Pain',
  'Gynaecology & Women''s Health',
  'Video Consultation',
  false,
  'Rachel Hodgson',
  '27-year-old female',
  ARRAY['Vaginal delivery 6 days ago'],
  ARRAY['Not on any regular medication','No Known Drug Allergy'],
  NULL,
  'Patient has booked an urgent video consultation to discuss breast pain that has been worsening over the past couple of days.',
  'Hello doctor, I''ve got pain in my right breast and it''s been getting worse.',
  'Your right breast has been painful for the past 2 days. It feels warm to touch and the pain keeps getting worse.',
  ARRAY['The breast pain is a constant dull ache affecting only your right breast. The left breast feels completely fine.','You had a temperature last night of 38 degrees Celsius. You''ve noticed a red patch on your right breast, starting near the nipple and spreading towards the upper part of the breast.','You haven''t noticed any lumps or rashes. You have been taking paracetamol but it hasn''t helped much.','You gave birth 6 days ago via vaginal delivery and everything went smoothly. Your baby, Sophie, is well and has no problems feeding or with her mouth. You are both breastfeeding and topping up with formula.'],
  'You live with your partner and your mum, who has been helping out since the birth. You feel very well supported at home. You are currently on maternity leave. You do not smoke, drink alcohol, or use illicit drugs.',
  'You''re not sure what''s causing it, but your mum mentioned it might be something that happens after having a baby.',
  'You''re worried about whether it''s safe to carry on breastfeeding.',
  'You''d like the doctor to tell you what''s going on and what to do next.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask if the symptoms are affecting one breast or both breasts.','Ask about the onset and progression of the breast pain, including whether it is getting better, worse, or staying the same.','Ask her to describe the pain and specifically ask about deep burning pain, as this may suggest ductal infection and may require milk culture.','Ask about the location of the pain and whether it is in one area or the whole breast.','Ask about associated symptoms such as redness, warmth, swelling, areas of hardness, or any lumps.','Ask about nipple discharge or nipple changes, including cracks or bleeding.','Ask about systemic symptoms including fever, chills, or feeling generally unwell.','Ask if she is breastfeeding. If yes, ask about any difficulties such as poor infant attachment or latching problems.','Ask about predisposing factors such as eczema, trauma, use of tight bras, feeding from one breast only, or mixed feeding.','Ask about red flag symptoms for breast cancer, including lumps in the armpit, unintentional weight loss, or night sweats.','Ask about medication use, including what analgesia has been taken so far.','Ask about social history, including smoking, alcohol use, illicit drug use, how she is coping at home, how the baby is doing, whether the baby is feeding and growing well, any fever in the baby, and any whitish coating on the baby''s tongue suggestive of oral thrush.','Explore her ideas, concerns, and expectations.','Make a diagnosis of lactational mastitis.'],
  ARRAY['Offer a face-to-face appointment to examine the breast and rule out an abscess that may require drainage.','Advise her that as her symptoms have worsened over the last 24 hours, antibiotics are indicated. Prescribe flucloxacillin 500 mg four times daily for 10 days. Reassure her that this is safe during breastfeeding and check for any allergies.','Advise that she can use ibuprofen for pain relief if there are no contraindications.','Advise her to continue breastfeeding from the affected breast if she is able, as this helps with recovery. If breastfeeding is too painful or the baby refuses to feed, advise her to hand express milk to maintain supply until she can resume breastfeeding.','If the nipple is cracked or painful, advise expressing milk from that breast until it heals.','Reassure her that it is safe to continue breastfeeding. The infection does not pass to the baby through breast milk, and breast milk contains protective factors that help the baby fight infections.','Advise her to rest and wear a well-fitting, supportive bra.','Offer to send leaflets and videos on breastfeeding techniques. If she continues to have difficulty, offer referral to a midwife or breastfeeding specialist for further support.','Provide safety-netting by advising her to seek urgent medical attention by contacting the GP surgery or NHS 111 out of hours if symptoms worsen, if she develops rigors, chills, a fast heart rate, feels increasingly unwell, or if there is no improvement within 48 hours of starting antibiotics.','Follow up in 10 days after completion of antibiotics.'],
  'It sounds like you''ve had quite an uncomfortable few days, Rachel, and I''m really glad you called in today. Breast pain in the first week or two after giving birth is something we take seriously, and based on what you''ve described — the redness spreading from around the nipple, the warmth, the worsening pain, and the fever you had overnight — this is looking very much like lactational mastitis. This is an infection of the breast tissue that can happen in breastfeeding mothers, usually when milk becomes blocked or bacteria enter through a cracked nipple.\n\nThe good news is that this is very treatable, and catching it early is exactly what we want to do. Because your symptoms have been getting worse over the past day or so, I do want to start you on a course of antibiotics. I''m going to prescribe flucloxacillin 500 mg, taken four times a day for 10 days. This antibiotic is safe to take while breastfeeding, so there''s no need to stop feeding Sophie. Before I send it through, can I just double-check whether you have any known allergies to antibiotics?\n\nI''d also like to see you in person — ideally today or tomorrow — so that we can examine the breast properly and make sure there isn''t a collection of fluid called an abscess forming underneath. An abscess sometimes needs to be drained and is something we''d want to pick up quickly.\n\nIn the meantime, please do continue feeding from the affected breast if you''re able to. I know that might sound counterintuitive when it''s painful, but keeping the milk moving is one of the most important things you can do to help the infection settle. The infection doesn''t pass to Sophie through your breast milk, and your milk actually contains antibodies that help protect her. If feeding becomes too painful or Sophie won''t latch on that side, hand expressing is a great alternative to keep the milk flowing until things improve.\n\nFor pain relief, paracetamol hasn''t been doing much for you, so I''d suggest trying ibuprofen as well — provided there''s no reason you can''t take it. It works as both a painkiller and an anti-inflammatory, which should help with the heat and swelling. Wearing a well-fitting, supportive bra and resting as much as you can — easier said than done with a newborn, I know — will also help.\n\nIf at any point over the next 48 hours things get worse rather than better — if you start shivering uncontrollably, develop a racing heart, feel very unwell, or there''s still no improvement after two days on the antibiotics — I''d like you to contact us again or call NHS 111 out of hours straight away. We''ll check in with you once you''ve finished the course of antibiotics in 10 days, but please don''t hesitate to get in touch sooner if you need to. You''re doing a brilliant job.',
  ARRAY['Lactational mastitis presents with unilateral breast pain, redness, warmth, and systemic symptoms such as fever in the postpartum period — it is the most likely diagnosis when these features occur within the first few weeks of breastfeeding.','Flucloxacillin 500 mg four times daily for 10 days is the first-line antibiotic for lactational mastitis; always check for penicillin allergy before prescribing.','Mothers should be advised to continue breastfeeding from the affected breast where possible — cessation of feeding can worsen milk stasis and increase the risk of abscess formation.','A face-to-face appointment is important to examine the breast and exclude an abscess, which would require surgical drainage.','Ibuprofen is a useful adjunct for pain relief and has anti-inflammatory properties particularly suited to mastitis; paracetamol alone is often insufficient.','Safety-netting is essential: advise the patient to seek urgent review if symptoms worsen, she develops rigors or feels very unwell, or there is no improvement within 48 hours of starting antibiotics.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  242,
  'Confidentiality in a Third-Party Query',
  'Ethics',
  'Telephone Consultation',
  false,
  'Dorothy Ashworth',
  '72-year-old female',
  ARRAY['Chronic Glaucoma','Hypertension'],
  ARRAY['Amlodipine 5 mg once daily','Latanoprost one drop once daily in both eyes','Allergic to penicillin'],
  'Letter from St. James''s Eye Unit – 4 weeks ago Re: Mrs Dorothy Ashworth | Age: 72-year-old female Dear Colleague, Mrs Dorothy Ashworth was seen in our clinic for assessment following an optometry referral due to raised intraocular pressure and suspected glaucoma. She remains asymptomatic in both eyes, with no reported visual disturbance, pain, or reduction in vision. On examination: (left eye) glaucomatous optic neuropathy. Based on the above findings, a diagnosis of chronic open-angle glaucoma has been made. She has been commenced on Latanoprost eye drops, to be used once daily at night. She has been advised to inform the Driver and Vehicle Licensing Agency (DVLA) of her diagnosis, and they will determine whether it is safe for her to continue driving. We will review her again in three months'' time to monitor her intraocular pressure and disease progression. Please do not hesitate to contact us if there are any concerns. Yours sincerely, Dr Priya Mehta, MBBS, FRCOphth, Consultant Ophthalmologist',
  'A telephone appointment has been booked by the patient''s daughter to discuss concerns about her mother.',
  'Hello doctor, I''d like to discuss some worries I have about my mum, if that''s alright.',
  'You noticed that your mum was given new eye drops. She used them for about 4 or 5 days and then stopped. You want to know what the drops are for, whether they are important, and if she has glaucoma, because she is no longer using them. You came across the medication online and think it might be used for glaucoma.',
  ARRAY['Your mum doesn''t know you''re calling, and she would be upset if she found out. She hasn''t given you permission to talk about her health, and you don''t have lasting power of attorney.','She told you the drops caused a stinging sensation in both eyes, which is why she stopped. You know the drops might be important for her eyes.','She hasn''t mentioned any problems with her vision and still seems to see well. However, you''ve noticed she hasn''t been driving recently. She mentioned she is waiting to hear back from the DVLA — ask the doctor whether this could be connected to the glaucoma.'],
  'She lives alone and manages all her daily activities independently, including shopping, cooking, and keeping the house. She doesn''t smoke or drink alcohol.',
  'You think she may have glaucoma based on what you found when you looked it up online.',
  'You''re worried that she has stopped taking her medication.',
  'You''d like the GP to tell you what condition she has and what you can do to help her take her medication.',
  ARRAY['If the doctor offers to contact your mother and let her know you called, say you''d prefer she didn''t know you discussed this. However, you''re happy to speak to her yourself and encourage her to contact the GP about her eye drops.'],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered to you by the doctor.',
  ARRAY['Clarify whether she has consent to discuss her mother''s medical information or has lasting power of attorney.','Acknowledge the daughter''s concern and explain confidentiality, including that you may not be able to share specific medical details without her mother''s consent.','Ask what she already understands about her mother''s condition.','Ask what she has noticed about her mother''s symptoms, including any changes in vision, eye pain, itching, swelling, photophobia, redness, headache, or difficulty carrying out daily activities.','Ask if she knows the reason her mother stopped using the eye drops.','Ask about any side effects from the eye drops, such as stinging, dry eyes, or eye colour changes.','Ask about any concerns regarding her mother''s memory or changes in behaviour that may affect her ability to manage medications independently.','Ask about the mother''s social history, including home situation, who she lives with, level of independence, smoking, alcohol use, and whether she is currently driving.','Explore the daughter''s ideas, concerns, and expectations.'],
  ARRAY['Acknowledge the daughter''s concerns and thank her for raising them.','Explain that as she does not have consent from her mother, you are unable to disclose the diagnosis or specific reasons for the prescribed eye drops.','Provide general information, explaining that eye drops like these are important in managing eye conditions and preventing long-term complications, and that stopping them without an alternative treatment may lead to worsening of the condition.','Encourage her to speak with her mother to book an appointment with the GP to discuss her concerns and side effects. Explain that you can liaise with the ophthalmology team through advice and guidance if needed.','Reassure her that if her mother is experiencing side effects, there may be alternative treatments available, and this can be reviewed.','Inform the daughter that, if she is happy for you to do so, you can contact her mother directly to share the concerns she has raised and speak with her about this.','Provide safety-netting by advising her to inform her mother that if she develops symptoms such as red eye, headache, or blurred vision, she should seek urgent medical attention by contacting the GP or NHS 111 if out of hours.'],
  'Thank you for calling today — it''s clear that you care a great deal about your mum''s health and wellbeing, and I really appreciate you raising these concerns. Before we go any further, I need to explain something important about how we handle patient information. As your mother''s GP, I have a duty of confidentiality to her, which means I''m not able to share specific details about her diagnosis or treatment without her permission. I hope you understand that this rule exists to protect all of our patients, including your mum.\n\nWhat I can tell you in general terms is that eye drops of the type you''ve described are often prescribed to manage conditions affecting the pressure inside the eye, and they play an important role in preventing long-term damage to vision. Stopping them without discussing an alternative with a doctor can sometimes allow the underlying condition to worsen over time. I can hear that this is something you''re understandably worried about.\n\nIt''s also worth knowing that stinging or discomfort when first starting eye drops is quite common, and in many cases it does settle after a few weeks. If it doesn''t, there are usually alternatives that can be tried. The important thing is that your mum is able to have that conversation with us directly so we can find a solution that works for her.\n\nThe most helpful next step would be for your mum to get in touch with us and book an appointment. We could then review the drops together with her, talk through any side effects she''s been experiencing, and make sure she has a treatment plan she''s comfortable with. If you''re able to encourage her to do that, it would be really valuable.\n\nIf you''re happy for me to do so, I could also contact your mum directly — I could let her know that someone close to her is concerned and invite her to come in and speak with us. That way, I wouldn''t need to mention who called. Would that feel like a helpful option, or would you prefer to speak to her yourself first?\n\nFinally, if at any point you notice that your mum develops any new symptoms — such as a red eye, a headache, or any change in her vision — please encourage her to contact us promptly, or call NHS 111 if it''s outside of normal surgery hours. We want to make sure she stays well.',
  ARRAY['When a third party contacts the GP about a patient, confidentiality must be maintained — specific clinical information cannot be disclosed without the patient''s consent or a legal authority such as lasting power of attorney.','General information can be shared (e.g. the importance of eye drops for managing eye conditions) without breaching confidentiality, as long as no specific diagnosis or treatment details are revealed.','The GP can offer to contact the patient directly to raise concerns without revealing who called, which balances confidentiality with patient safety.','Always clarify early in the consultation whether the caller has consent or lasting power of attorney, as this determines how much information can be shared.','Medication side effects (such as stinging with Latanoprost) are a common reason for non-adherence — alternatives should be explored rather than simply advising the patient to persevere.','Safety-netting is still relevant in third-party calls — advise the caller to encourage the patient to seek urgent help if symptoms such as red eye, headache, or visual disturbance develop.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  243,
  'Headache and Request for Antibiotics',
  'Neurology',
  'Video Consultation',
  false,
  'Gemma Sutton',
  '28-year-old female',
  ARRAY['None recorded'],
  ARRAY['Nexplanon (inserted 1 year ago)','No Known Drug Allergy'],
  NULL,
  'Patient has booked an urgent video consultation to discuss persistent headaches and is requesting antibiotics.',
  'Hello doctor, I think I''ve got sinusitis and I''d like some antibiotics please.',
  'You''ve been getting headaches at the front of your head for the past 10 days. A colleague at work had exactly the same thing and was told it was sinusitis and given antibiotics, so you think that''s probably what this is.',
  ARRAY['You had a runny nose about 2 weeks ago, which has now completely cleared up. But the headaches have carried on. The pain goes across your whole forehead, feels like a tight band around your head, and comes and goes throughout the day. There''s no nausea or vomiting.','You don''t have any facial pain, blocked nose, runny nose, or fever. No blurred vision either.','You''ve tried paracetamol but it hasn''t really helped.','Your last menstrual period was about a week ago.'],
  'You work as an estate agent and started a new job about 2 months ago. It''s been quite demanding getting to grips with everything but you''re enjoying it. You live with your boyfriend. You don''t smoke, drink alcohol, or use illicit drugs.',
  'You think you have sinusitis.',
  'You''re worried about sinusitis.',
  'You''d like the doctor to prescribe antibiotics. If the doctor asks about time off work, explain that you can''t really take any time off at the moment as you''re still settling in to your new role.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset, location, character, and progression of the headache.','Ask about associated symptoms including nausea, vomiting, and photophobia.','Ask about symptoms of sinusitis, including nasal congestion, facial pain or pressure, reduced sense of smell, fever, recent flu-like illness, or purulent nasal discharge.','Ask about triggers for the headache, including recent stress, caffeine intake, missed meals, or dehydration.','Ask about red flag symptoms, including visual changes, neck stiffness, confusion, rash, recent head trauma, or focal neurological symptoms such as weakness, tingling, or slurred speech.','Ask about medication use, including analgesia taken, frequency, and response.','Ask about menstrual history and any relation of headaches to the menstrual cycle.','Ask about any past history of similar headaches.','Ask about the severity of pain and its impact on daily activities.','Ask about social history, including alcohol use, smoking, and illicit drug use.','Explore the patient''s ideas, concerns, and expectations.','Make a working diagnosis of tension-type headache.'],
  ARRAY['Acknowledge her symptoms and explain that her symptoms are not typical of sinusitis and are more in keeping with a tension-type headache.','Advise her to keep a symptom diary to help identify potential triggers.','Advise that she can take ibuprofen 400 mg three times daily for pain relief, which can be taken alongside paracetamol if needed. Inform her that it is available over the counter, and advise her about possible side effects such as stomach upset, recommending that she takes it with or after food.','Discuss the role of stress as a contributing factor and advise strategies to manage this, such as regular exercise, yoga, and mindfulness.','Advise reducing screen time where possible, as eye strain can contribute to headaches.','Encourage her to speak with her workplace about workload and support, and discuss the possibility of adjustments or time off if needed.','Provide safety-netting by advising her to seek medical attention by contacting the GP surgery or NHS 111 if out of hours if headaches worsen, become persistent, or if she develops red flag symptoms such as visual changes, vomiting, neurological symptoms, or fever.','Arrange follow-up in 4 weeks to review her symptoms and progress.'],
  'I can hear that these headaches have been really persistent and frustrating, especially when you''re trying to get settled into a new job. I''m glad you came in today so we can get to the bottom of what''s going on, Gemma. Having looked at everything you''ve described, I don''t think this is actually sinusitis. The symptoms that would point towards sinusitis — things like facial pain or pressure, a blocked nose, thick nasal discharge, or a fever — aren''t really present here. The runny nose you had a fortnight ago sounds more like a viral cold that has since cleared up.\n\nWhat your headaches are actually sounding more like is something called a tension-type headache. This is one of the most common types of headache, and the way you''ve described it — a tight band across the whole forehead, coming and going, without nausea or visual changes — fits this pattern really well. Tension headaches are often triggered or made worse by stress, tiredness, too much screen time, or changes to your routine, all of which can come with starting a new job.\n\nBecause of this, antibiotics wouldn''t actually be the right treatment here — they work against bacterial infections, and a tension headache isn''t caused by an infection. What I''d suggest instead is trying ibuprofen 400 mg three times a day with or after food, as this can be more effective for this type of headache than paracetamol alone, and the two can be taken together if needed. You can pick this up over the counter. Just be aware it can occasionally cause some stomach discomfort, so taking it with food is a good idea.\n\nI''d also encourage you to keep a simple headache diary — just jotting down when the headaches happen, how long they last, and what you were doing beforehand. This can be really useful for spotting patterns and identifying any triggers. Things like staying well hydrated, eating regular meals, taking proper breaks from screens, and getting some fresh air and exercise can all make a real difference.\n\nI understand that taking time off isn''t an option right now, but it might be worth having a quiet word with your manager about workload — not necessarily about taking leave, but just to make sure you have enough support while you''re finding your feet. Stress is a very real factor in tension headaches.\n\nIf the headaches get worse rather than better, become very severe, or you develop anything new — such as visual changes, vomiting, neck stiffness, or any neurological symptoms like tingling or weakness — please don''t wait: contact us straight away or call NHS 111 if it''s outside hours. Otherwise, let''s arrange a follow-up in about four weeks to see how you''re getting on.',
  ARRAY['Tension-type headache is characterised by a bilateral, band-like pressure or tightening sensation without nausea or photophobia — it is the most common headache type and should not be confused with sinusitis.','Sinusitis requires features such as facial pain or pressure, purulent nasal discharge, nasal congestion, and often fever — a preceding cold without these ongoing features does not indicate bacterial sinusitis.','Antibiotics are not indicated for tension-type headache; ibuprofen 400 mg three times daily (taken with food) is an appropriate first-line analgesic, and can be combined with paracetamol.','Red flag headache features requiring urgent review include sudden-onset severe headache, progressive worsening, focal neurological symptoms, neck stiffness, fever, or headache with visual disturbance.','Stress, poor sleep, dehydration, and excessive screen time are common modifiable triggers for tension-type headache and should be explored and addressed.','A headache diary is a useful tool to identify triggers and monitor progression, and follow-up should be arranged to reassess if symptoms do not improve.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  244,
  'Suspected Drug Reaction in a Patient with Gout',
  'Dermatology',
  'Telephone Consultation',
  false,
  'Philip Hartley',
  '58-year-old male',
  ARRAY['Gout'],
  ARRAY['Allopurinol 100 mg once daily','No Known Drug Allergy'],
  'Telephone consultation with Dr Sarah Whitmore (Clinical Practitioner role) - 10 days ago. Presenting complaint: Patient booked this appointment to discuss urate-lowering therapy. Last urate level 1 week ago: 392 micromol/L. We discussed the benefits of starting allopurinol, and the patient is willing to proceed. He understands the potential side effects, including the risk of allopurinol precipitating a gout flare. Colchicine prophylaxis was offered, but the patient prefers not to take additional medication and is happy to start allopurinol, with a plan to use acute treatment if a flare occurs. Plan: Start allopurinol 100 mg once daily. Repeat urate levels in 4 weeks time.',
  'Patient has booked an urgent telephone consultation and has sent a photograph of a rash to be reviewed.',
  'Hello doctor, have you had a chance to look at the photo of the rash I sent through?',
  'You noticed the rash started about 2 days ago. It began on your stomach and has spread to your neck, both arms and your back. It''s very itchy and is disturbing your sleep.',
  ARRAY['The rashes are flat and red.','You haven''t been in contact with anyone with a similar rash. You don''t have a fever, and there are no rashes on your palms, mouth, face, genitals, or legs.','You don''t have any shortness of breath or facial swelling.','You''re still taking the allopurinol and took it again this morning.','You are not taking any other medications.'],
  'You don''t smoke, don''t drink alcohol, and don''t use illicit drugs. You work as a financial adviser and live with your wife.',
  'You think the rash might be caused by allopurinol, as you read about this in the information leaflet that came with the medication.',
  'The rash is extremely itchy and is stopping you from sleeping properly.',
  'You''d like the GP to prescribe something to help.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset and progression of the rash, including when it started and how quickly it has spread.','Ask about the appearance of the rash, including whether it is raised, flat, blotchy, or blistering.','Ask if the skin is dry and whether there is any discharge from the rash.','Ask about associated symptoms such as itching, pain, or burning.','Ask about symptoms suggestive of anaphylaxis or angioedema, including facial swelling, lip or tongue swelling, shortness of breath, or wheeze.','Ask about symptoms suggestive of Stevens-Johnson syndrome, including mouth ulcers, genital sores, blisters, skin peeling, fever, palpitations, or feeling generally unwell.','Ask whether the rash involves the palms or soles.','Ask about any recent flu-like illness, sore throat, or diarrhoea to rule out a viral rash such as measles.','Ask if the rash started after initiating allopurinol and whether he is taking any over-the-counter medications.','Ask about any new soaps, creams, detergents, foods, or other possible allergens.','Ask about contact with anyone with a similar rash.','Ask about the impact on sleep and daily activities.','Ask about social history, including smoking, alcohol use, and illicit drug use.','Explore the patient''s ideas, concerns, and expectations.','Make a working diagnosis of likely allopurinol-induced maculopapular drug rash.'],
  ARRAY['Advise the patient to stop allopurinol immediately.','Offer a non-sedating antihistamine such as cetirizine. Inform him that although it is generally non-drowsy, it can occasionally cause mild drowsiness, and advise him not to drive or operate machinery if he feels drowsy.','Offer a topical emollient to soothe the skin (for example, Epimax or Oilatum cream for moist skin, or Cetraben or Diprobase ointment for dry skin).','Consider adding a topical steroid, such as a mild to moderate potency steroid, if symptoms are not controlled with emollients alone.','Advise that once the rash has settled, alternative urate-lowering therapy can be considered, such as febuxostat.','Inform him that you will document allopurinol as a drug allergy in his records and advise him to avoid it in the future.','Provide safety-netting and advise that if the rash worsens, or if he develops blistering, fever, mouth ulcers, facial or tongue swelling, or difficulty breathing, he should call 999 or attend A&E urgently.','Arrange follow-up in 2 weeks to ensure the rash has settled and to discuss alternative urate-lowering therapy.'],
  'Thank you for sending that photograph through — it''s been really helpful to see. Based on what you''ve described, with the rash starting on your stomach and spreading to your neck, arms, and back over the past two days, and given the timing in relation to when you started allopurinol, this does look very much like a drug rash caused by allopurinol. This is a known side effect and something we take seriously, so I''m glad you got in touch promptly.\n\nThe most important thing right now is that you stop taking allopurinol straight away — please don''t take any more doses. I''ll be adding allopurinol to your medical records as a drug allergy, so that it is flagged in future and you won''t be prescribed it again. You mentioned in the leaflet that you''d read about this possibility, and you were absolutely right to make that connection.\n\nTo help with the itching, I''m going to prescribe cetirizine, which is a non-sedating antihistamine. It shouldn''t make you drowsy, though in a small number of people it can cause mild sleepiness, so please avoid driving or using machinery if you feel any of that. For the skin itself, I''d also like to suggest a moisturising emollient — something like Oilatum or Epimax cream — which can help soothe and settle the irritation. If the itching isn''t controlled with those alone, we may consider adding a mild to moderate topical steroid cream as well.\n\nOnce the rash has fully settled down, we''ll need to revisit the question of managing your gout. There is an alternative urate-lowering medication called febuxostat, which works in a similar way to allopurinol but through a different mechanism, and this would be something we can discuss at your follow-up. We''ll aim to bring you back in about two weeks to check that the rash has cleared.\n\nFinally, and this is very important: if at any point the rash gets significantly worse, you develop any blistering, peeling of the skin, ulcers in your mouth, swelling of your face, lips, or tongue, or you have any difficulty breathing, please do not wait — call 999 or go straight to A&E. These could be signs of a more serious reaction that requires emergency treatment. I don''t expect that to happen, but I want to make sure you know what to watch out for.',
  ARRAY['A maculopapular rash appearing within weeks of starting allopurinol should be treated as an allopurinol-induced drug reaction until proven otherwise — allopurinol must be stopped immediately.','Always ask specifically about features of Stevens-Johnson syndrome (mouth ulcers, genital sores, blistering, skin peeling, fever) and anaphylaxis (facial swelling, breathing difficulty) when assessing a drug rash, as these require emergency management.','Cetirizine is a suitable non-sedating antihistamine for drug rash; topical emollients and mild to moderate topical steroids can also be used for symptom control.','Allopurinol should be documented as a drug allergy in the patient''s medical record and the patient advised to avoid it permanently.','Febuxostat is an appropriate alternative urate-lowering therapy for patients who cannot tolerate allopurinol.','Safety-netting is critical: patients must be advised to call 999 or attend A&E immediately if they develop blistering, peeling, mouth ulcers, facial swelling, or difficulty breathing.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  245,
  'Anxiety About Dying in a Palliative Patient',
  'Elderly Medicine & Palliative Care',
  'Telephone Consultation',
  false,
  'Carolyn Barrett',
  '62-year-old female',
  ARRAY['Metastatic Breast Cancer','Has DNACPR in place'],
  ARRAY['Oramorph 10 mg/5 ml, 2.5 ml (5 mg) every 4 hours as required for pain','Senna 15 mg once daily','Laxido 2 sachets once daily','No Known Drug Allergy'],
  'Oncology letter – 4 weeks ago. Dear GP, Re: Carolyn Barrett, 62-year-old female. Thank you for your ongoing care of this patient. Mrs Barrett has a diagnosis of advanced breast cancer, which has now progressed with metastatic spread to the liver, bones, and brain. Despite receiving palliative chemotherapy and radiotherapy, unfortunately her disease has not responded to treatment and has continued to progress. Following careful discussion with Mrs Barrett, she is now considered to be in the palliative phase of her illness. She has been informed of her prognosis, which is estimated to be in the region of weeks to months, and she demonstrates a clear understanding of this. I would be grateful if you could liaise with the community palliative care team to ensure that appropriate support is in place. If you have any concerns or queries regarding her care, please do not hesitate to contact me. Yours sincerely, Dr Aisha Patel, Consultant Clinical Oncologist.',
  'Patient has booked a routine telephone consultation to discuss her emotional wellbeing following a recent visit from the district nursing team.',
  'Hello doctor, the district nurse suggested I give you a call.',
  'You recently had a visit from the district nurses as part of your community palliative care. During that visit, you mentioned that you''ve been feeling low and very anxious about dying, because you''re not sure when it will happen. You were told your prognosis is weeks to months, and the uncertainty is really getting to you. The nurse thought it would be helpful for you to speak with your GP.',
  ARRAY['Your mood has been low, and your mind keeps dwelling on thoughts about dying. This makes you feel very anxious and sometimes affects your sleep. These feelings started about 4 weeks ago after your last appointment with the oncologist.','What worries you most about dying is feeling out of control — particularly the fear of going to sleep one night and not waking up.','You are still managing to eat and drink. You do have generalised bone pain, but the Oramorph helps keep it under control. Your bowels are regular and you are passing urine normally.','You are not struggling to look after yourself, you have no financial difficulties, and you are managing well at home.'],
  'You live with your husband, who has been wonderfully supportive throughout everything. You don''t smoke, drink alcohol, or use illicit drugs.',
  'You''re not really sure why you feel this way — you thought you''d come to terms with your diagnosis, but lately the anxiety has crept back.',
  'You''re scared about dying.',
  'You''d like the GP to help you find ways to cope with how you''re feeling.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Acknowledge her concerns and explore her mood, including the onset, duration, and progression of low mood.','Ask about symptoms of depression, including poor sleep, low energy, reduced appetite, loss of interest, or reduced concentration.','Ask about symptoms of anxiety, including constant worry, restlessness, panic episodes, or physical symptoms such as palpitations.','Explore her thoughts about dying, including what specifically worries her and any fears about the process of dying. Note: common fears include loss of control, dying suddenly in their sleep, experiencing pain, becoming a burden to others, anxiety about leaving loved ones behind, or uncertainty about what happens during the dying process.','Ask sensitively about suicidal thoughts or thoughts of self-harm.','Ask about the impact of symptoms on daily functioning and quality of life.','Ask about other common palliative symptoms, including pain, constipation, nausea, vomiting, difficulty breathing, dry mouth, or headache.','Ask about support systems, including her husband, family, and community or palliative care team involvement.','Ask about social history, including home situation, finances, support at home, smoking, alcohol use, and illicit drug use.','Ask about any previous history of mental health problems.','Explore her ideas, concerns, and expectations.','Make a working diagnosis of adjustment disorder with low mood and anxiety.'],
  ARRAY['Acknowledge her feelings with empathy and validate her fears about dying.','Reassure her that what she is experiencing is understandable given her situation.','Offer clear explanation of the dying process to reduce uncertainty and fear. Inform her that as her condition progresses, people typically become gradually more tired and sleepy, and that this is usually a gentle and progressive process rather than something sudden or frightening.','Explain that to help her feel more in control, we can carry out advance care planning, which allows her to document her wishes and preferences for future care in case she is unable to make decisions later, ensuring that all care provided is in line with her preferences.','Offer referral for talking therapy with a psychologist experienced in palliative care. Explain that this can help her explore her thoughts, feel more in control, and manage her anxiety and low mood.','Explain that many people do well with talking therapy alone, but if her symptoms begin to significantly affect her, medication can be considered. Options include mirtazapine, which may help with sleep and mood, or an SSRI such as sertraline.','Offer another telephone consultation or home visit to discuss advance care planning. Also explain that we can prescribe "just in case" medications, which are used to manage common symptoms that may arise as her condition progresses.','Inform her that she may be eligible for additional support, including benefits. Explain that an SR1 form can be completed, and offer to liaise with a social prescriber to assist with this.','Provide her with the local palliative care emergency contact number for easy access to the district nurse or GP in case she has any concerns or worsening symptoms.','Provide safety-netting by advising her to seek help if her mood worsens, she develops thoughts of self-harm, or if her symptoms become overwhelming.','Arrange follow-up in 2 weeks to ensure she has appropriate support in place and to review any ongoing concerns.'],
  'Thank you so much for calling today. I can hear how much courage it takes to talk about these feelings, and I want you to know that everything you''re describing makes complete sense given what you''ve been through. Feeling anxious and low in the context of a life-limiting illness is not a sign of weakness — it is a very natural human response, and you are absolutely not alone in feeling this way.\n\nWhat you''ve described — the low mood, the difficulty sleeping, the mind returning again and again to thoughts about dying and what that will look like — sounds very much like what we call an adjustment disorder. This is where the emotional weight of a difficult situation begins to affect how we feel day to day. It does not mean you are not coping; it means that what you are facing is genuinely very hard.\n\nOne of the things that many people find most frightening is exactly what you''ve described — the uncertainty, and particularly the fear of losing control over what happens. I want to try and offer you a little reassurance about that. For most people, as their illness progresses, the process of dying is a gradual one. People tend to become more sleepy and tired over time, and it is generally a gentle, progressive process rather than something that happens suddenly and without warning. I hope that is a little comforting, even if it doesn''t take the fear away entirely.\n\nOne thing that can really help with that sense of control is something called advance care planning. This is where we sit down together — or I can arrange a home visit if that would be easier — and we write down your wishes for how you''d like to be cared for as things progress. This means that whatever happens, your preferences will be known and respected. We can also discuss prescribing what are called "just in case" medications in advance, which are kept at home so that if you develop any distressing symptoms, the district nurses can administer them quickly without any delay.\n\nI''d also very much like to refer you to a psychologist who specialises in working with people in your situation. Talking therapy of this kind has been shown to be really helpful for managing anxiety and low mood, and it can also give you more tools to feel in control of your thoughts. If at any point you feel that talking therapy alone isn''t enough, there are medications we can consider as well — for example, mirtazapine, which can help with both sleep and mood, or an SSRI such as sertraline.\n\nPlease do make use of the palliative care emergency contact number — the district nurses and the team around you are there precisely for moments like this. And I''d like to speak with you again in about two weeks to see how you''re getting on and make sure everything is in place. In the meantime, if your mood gets much worse or you have any thoughts of harming yourself, please reach out straight away.',
  ARRAY['Anxiety and low mood are common in palliative patients and most often represent an adjustment disorder — this should be explored with empathy and not dismissed as an inevitable part of dying.','Exploring specific fears about the dying process (e.g. loss of control, dying suddenly in sleep, pain) allows the GP to address these with targeted reassurance and practical information.','Advance care planning empowers patients by allowing them to document their wishes for future care, increasing their sense of control.','Talking therapy with a palliative care psychologist is the preferred first-line treatment for adjustment disorder; pharmacological options such as mirtazapine or sertraline can be added if symptoms are not controlled.','"Just in case" medications should be discussed proactively with palliative patients to allow rapid symptom management at home without delays.','The SR1 form can be completed for patients with a terminal diagnosis to enable access to benefits, and social prescribers can assist with this process.'],
  NULL
);

INSERT INTO stations (
  number, title, subject, consultation_type, published,
  patient_name, patient_age, pmh, medications_and_allergies, recent_notes,
  reason_for_consultation, opening_statement, if_asked_further,
  only_if_asked, social_history, ice_ideas, ice_concerns, ice_expectations,
  scenarios, question_for_doctor, role_player_instruction,
  data_gathering, management, example_explanation, key_takeaways, editor_video_url
) VALUES (
  246,
  'Severe Unilateral Facial Pain',
  'Neurology',
  'Video Consultation',
  false,
  'Simon Warwick',
  '44-year-old male',
  ARRAY['None recorded'],
  ARRAY['Not on any current medication','No Known Drug Allergy'],
  NULL,
  'Patient has booked an urgent video consultation to discuss severe facial pain that has been ongoing for several weeks.',
  'Hello doctor, I''ve been having these headaches for about 4 weeks now and they''re really starting to get me down.',
  'The pain is on the left side of your face, around the temple area, and it''s not improving.',
  ARRAY['The pain is sharp and lasts about 2 minutes at a time, then goes away. You can have up to 15 or more of these attacks in a single day.','The pain spreads to your left cheek.','It''s noticeably worse in the morning, particularly when you''re washing your face, brushing your teeth, or sometimes when you''re eating. That''s what made you go to the dentist — but they checked your teeth thoroughly and said everything looked fine.','The pain is very severe. You''ve tried both paracetamol and ibuprofen but neither has made any difference.','You don''t have nausea or vomiting.'],
  'You don''t smoke, drink alcohol, or use illicit drugs. You live with your wife and three children. You work in finance and your job is fairly steady — not especially stressful.',
  'You think it might be some kind of migraine.',
  'The pain is making you anxious about eating, because you''re worried that chewing might set off another attack.',
  'You''d like the GP to help you get on top of this.',
  ARRAY[]::text[],
  NULL,
  'Say NO to any other questions or symptoms asked about outside of the details already provided in the scenario. Accept anything offered by the doctor.',
  ARRAY['Ask about the onset, location, duration, character, and progression of the pain, including whether it is getting better, worse, or staying the same.','Ask if the pain radiates anywhere.','Ask about triggers such as touching the face, brushing teeth, chewing, speaking, or exposure to cold air.','Ask about any relieving factors.','Ask about associated neurological symptoms such as facial numbness, weakness, visual changes, or hearing problems.','Ask about sinus-related symptoms such as nasal congestion, runny nose, nasal discharge, facial pressure, or fever.','Ask about symptoms of migraine, including nausea, vomiting, photophobia, or aura.','Ask about dental symptoms or recent dental procedures.','Ask about any history of trauma or infection affecting the face.','Ask about red flag symptoms such as unintentional weight loss, night sweats, or loss of appetite to rule out malignancy.','Ask about social history, including smoking, alcohol use, and illicit drug use.','Ask about the impact of the pain on daily activities.','Explore the patient''s ideas, concerns, and expectations.','Make a working diagnosis of trigeminal neuralgia.'],
  ARRAY['Offer a face-to-face appointment to examine the cranial nerves of the face.','Offer treatment with carbamazepine, starting at 100 mg twice daily and titrating up as needed for symptom control.','Explain that carbamazepine is a medication commonly used for seizures but is also effective in treating nerve-related pain such as trigeminal neuralgia.','Arrange baseline blood tests before starting treatment, including full blood count and liver function tests.','Inform the patient about common side effects such as dizziness, drowsiness, dry mouth, and gastrointestinal upset.','Explain rare but important side effects, including a drop in white blood cells (agranulocytosis). Advise the patient that if they develop symptoms such as a sore throat, fever, or feel generally unwell, they should seek medical attention promptly.','Provide safety-netting by advising the patient to seek urgent help by contacting the GP surgery or NHS 111 if symptoms worsen or if they develop red flag symptoms such as visual disturbance, hearing changes, or facial weakness.','Arrange follow-up in 2 weeks to assess symptom control and response to treatment.'],
  'Thank you for getting in touch — four weeks of pain like this must have been really wearing, and I can see why it''s getting you down. Based on what you''ve described, Simon, I think what you''re experiencing is actually something called trigeminal neuralgia rather than migraine. Let me explain what that means.\n\nThe trigeminal nerve is the main nerve responsible for sensation across the face. When this nerve becomes irritated or compressed, it can cause very sudden, severe, sharp pain — often described as electric-shock-like — that typically lasts a matter of seconds to a couple of minutes and then stops, before returning again. The fact that your pain is on one side of your face, radiates to your cheek, is triggered by everyday things like washing your face, brushing your teeth, or chewing, and that your dentist found nothing wrong with your teeth — all of this fits very well with trigeminal neuralgia.\n\nI''d like to arrange for you to come in to see me in person so that I can examine the nerves in your face properly — this helps to confirm the diagnosis and make sure there''s nothing else we need to look into. I''d also like to arrange some baseline blood tests before we start any treatment, specifically a full blood count and liver function tests.\n\nIn terms of treatment, the medication we use for trigeminal neuralgia is called carbamazepine. It''s actually a drug that is more commonly known for treating epilepsy, but it is highly effective for nerve pain of this kind. We would start you at 100 mg twice a day and adjust the dose gradually until we find the level that gives you the best symptom control. Common side effects can include dizziness, drowsiness, dry mouth, and some stomach upset, particularly when you first start taking it, so it''s worth being aware of those.\n\nThere is also a rare but important side effect I want to make sure you know about: carbamazepine can in very rare cases reduce your white blood cell count, which are the cells that help fight infection. If at any point you develop a sore throat, a fever, or simply feel very unwell, please contact us promptly rather than waiting — it''s something we would want to check.\n\nI''ll book you in for a review in two weeks to see how you''re responding to the medication. If in the meantime your symptoms worsen significantly, or you develop anything new such as visual disturbance, hearing changes, or weakness in the face, please get in touch with us straight away or call NHS 111 if it''s out of hours.',
  ARRAY['Trigeminal neuralgia presents with brief, severe, lancinating unilateral facial pain triggered by light touch or everyday activities such as chewing, washing, or brushing teeth — it is frequently misdiagnosed as dental pain.','Carbamazepine 100 mg twice daily (titrated as needed) is the first-line treatment for trigeminal neuralgia; it acts on voltage-gated sodium channels to reduce nerve excitability.','Baseline full blood count and liver function tests should be arranged before starting carbamazepine, and the patient should be counselled about common side effects (dizziness, drowsiness, GI upset) and the rare but serious risk of agranulocytosis.','Patients should be advised to seek prompt medical attention if they develop signs of infection (sore throat, fever, feeling unwell) while on carbamazepine, as this may indicate a drop in white blood cells.','A face-to-face appointment to examine the cranial nerves is essential in suspected trigeminal neuralgia to confirm the diagnosis and exclude sinister causes such as a mass lesion.','Red flag features requiring urgent review include progressive neurological symptoms, hearing changes, visual disturbance, or facial weakness, which may indicate an underlying structural cause.'],
  NULL
);

